import React, { useState } from "react";
import axios from "axios";

/**
 * 👑 ADMIN PORTAL - License Management
 */
function App() {
  const [isAdmin, setIsAdmin] = useState(false);
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");

  // New License State
  const [newKey, setNewKey] = useState("");
  const [expiry, setExpiry] = useState("");
  const [success, setSuccess] = useState("");

  const handleLogin = (e) => {
    e.preventDefault();
    if (username === "admin" && password === "admin123") {
      setIsAdmin(true);
      setError("");
    } else {
      setError("❌ Invalid Admin Credentials");
    }
  };

  const generateLicense = async (e) => {
    e.preventDefault();
    setSuccess("");
    setError("");

    try {
      const res = await axios.post("http://localhost:5000/add-license", {
        key: newKey,
        expiry: expiry
      });

      if (res.data.success) {
        setSuccess("✅ License Created Successfully!");
        setNewKey("");
        setExpiry("");
      }
    } catch (err) {
      setError("❌ Failed to create license: " + (err.response?.data?.error || err.message));
    }
  };

  if (!isAdmin) {
    return (
      <div className="admin-login-overlay">
        <div className="admin-login-card">
          <h1>🔐 Admin Portal</h1>
          <p>Global License Management</p>
          <form onSubmit={handleLogin}>
            <input 
              type="text" 
              placeholder="Username" 
              value={username} 
              onChange={(e) => setUsername(e.target.value)} 
            />
            <input 
              type="password" 
              placeholder="Password" 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
            />
            <button type="submit">Unlock Portal</button>
          </form>
          {error && <p className="error">{error}</p>}
        </div>
      </div>
    );
  }

  return (
    <div className="admin-dashboard">
      <aside className="admin-sidebar">
        <h2>👑 Swarna Admin</h2>
        <nav>
          <div className="active">Generate License</div>
          <div>Active Licenses</div>
          <div>System Logs</div>
        </nav>
        <button className="logout" onClick={() => setIsAdmin(false)}>Sign Out</button>
      </aside>

      <main className="admin-content">
        <header>
          <h1>Create New License</h1>
          <p>Issue new activation keys to clients</p>
        </header>

        <section className="form-section">
          <div className="card">
            <form onSubmit={generateLicense}>
              <div className="input-group">
                <label>License Key</label>
                <input 
                  type="text" 
                  placeholder="e.g. GOLD-2026-XXXX" 
                  value={newKey} 
                  onChange={(e) => setNewKey(e.target.value.toUpperCase())}
                  required
                />
              </div>

              <div className="input-group">
                <label>Expiry Date</label>
                <input 
                  type="date" 
                  value={expiry} 
                  onChange={(e) => setExpiry(e.target.value)}
                  required
                />
              </div>

              <button type="submit">Create License Key</button>
            </form>
            {success && <p className="success">{success}</p>}
            {error && <p className="error">{error}</p>}
          </div>
        </section>
      </main>
    </div>
  );
}

export default App;
